column.value:
{
  "pageDescription": "Sample Creation & Full Metadata Capture",
  "dataPoints": {
    "sampleIdentity": {
      "accessionNumber": {"type": "text", "label": "Pathology Accession Number", "generated": true, "required": true},
      "barcode": {"type": "barcode", "label": "Barcode/Label", "generated": true},
      "sampleCategory": {"type": "choice", "label": "Sample Category", "options": ["Clinical diagnostic", "Research"], "required": true}
    },
    "sampleSource": {
      "sourceFacility": {"type": "choice", "label": "Source Facility", "options": ["Alert Hospital", "Research project"], "required": true},
      "receivedDateTime": {"type": "dateTime", "label": "Received Date & Time", "required": true},
      "receivedBy": {"type": "text", "label": "Received By (Staff Name)", "required": true}
    },
    "specimenType": {
      "type": "reference",
      "label": "Specimen Type",
      "source": "type_of_sample",
      "categories": {
        "histopathology": ["FFPE tissue block", "Fresh biopsy", "Surgical resection"],
        "cytopathology": ["FNA", "Body fluid (pleural)", "Body fluid (peritoneal)", "Body fluid (pericardial)", "Body fluid (CSF)", "Urine", "Sputum", "Cervical smear"],
        "hematology": ["EDTA blood (peripheral smear)"],
        "research": ["Human tissue (fresh)", "Human tissue (frozen)", "Human tissue (FFPE)", "Animal tissue (mouse footpad)", "Animal tissue (nerve)", "Bacterial/cellular pellet", "Primary cell culture"]
      },
      "required": true
    },
    "clinicalMetadata": {
      "patientId": {"type": "text", "label": "Patient ID", "conditionalOn": "sampleCategory == Clinical diagnostic", "required": false},
      "requestingClinician": {"type": "text", "label": "Requesting Clinician", "conditionalOn": "sampleCategory == Clinical diagnostic", "required": false},
      "collectionDateTime": {"type": "dateTime", "label": "Collection Date & Time", "required": true},
      "specimenSite": {"type": "text", "label": "Specimen Site", "required": false},
      "clinicalDetails": {"type": "textarea", "label": "Clinical Details", "conditionalOn": "sampleCategory == Clinical diagnostic", "required": false}
    },
    "researchMetadata": {
      "studyId": {"type": "text", "label": "Study ID", "conditionalOn": "sampleCategory == Research", "required": false},
      "piName": {"type": "text", "label": "PI Name", "conditionalOn": "sampleCategory == Research", "required": false},
      "participantAnimalId": {"type": "text", "label": "Participant/Animal ID", "conditionalOn": "sampleCategory == Research", "required": false},
      "ethicalApprovalRef": {"type": "text", "label": "Ethical Approval Reference", "conditionalOn": "sampleCategory == Research", "required": false}
    }
  },
  "systemActions": ["Generate unique pathology accession number", "Generate label/barcode", "Set status: Created - Pending QC", "Print label"],
  "nextPage": "Sample Quality Control"
}

{
  "pageDescription": "Sample Quality Control (QC)",
  "dataPoints": {
    "histologyQC": {
      "fixativeUsed": {"type": "choice", "label": "Fixative Used", "options": ["10% NBF", "Formalin", "Other"], "conditionalOn": "specimenType.category == histopathology"},
      "fixativeRatio": {"type": "text", "label": "Fixative Ratio", "placeholder": "e.g., 10:1", "conditionalOn": "specimenType.category == histopathology"},
      "fixationDuration": {"type": "text", "label": "Fixation Duration", "conditionalOn": "specimenType.category == histopathology"},
      "tissueIntegrity": {"type": "choice", "label": "Tissue Integrity", "options": ["Intact", "Compromised"], "conditionalOn": "specimenType.category == histopathology"}
    },
    "cytologyQC": {
      "containerIntegrity": {"type": "choice", "label": "Container Integrity", "options": ["Intact", "Compromised"], "conditionalOn": "specimenType.category == cytopathology"},
      "preservativeType": {"type": "text", "label": "Preservative Type", "placeholder": "e.g., Cytolyt", "conditionalOn": "specimenType.category == cytopathology"},
      "volume": {"type": "number", "label": "Volume (mL)", "conditionalOn": "specimenType.category == cytopathology"},
      "clotPresence": {"type": "choice", "label": "Clot Presence", "options": ["None", "Present"], "conditionalOn": "specimenType.category == cytopathology"}
    },
    "bloodQC": {
      "clotCheck": {"type": "choice", "label": "Clot Check in EDTA Tube", "options": ["No clot", "Clot present"], "conditionalOn": "specimenType.category == hematology"}
    },
    "researchQC": {
      "consentVerified": {"type": "boolean", "label": "Consent Verified", "conditionalOn": "sampleCategory == Research"},
      "storageMedium": {"type": "choice", "label": "Storage Medium", "options": ["OCT", "RNAlater", "None", "Other"], "conditionalOn": "sampleCategory == Research"},
      "sampleTypeMatchesProtocol": {"type": "boolean", "label": "Sample Type Matches Protocol", "conditionalOn": "sampleCategory == Research"}
    },
    "tissueBlockQC": {
      "surfaceQuality": {"type": "choice", "label": "Surface Quality", "options": ["Smooth", "Cracks", "Bubbles"]},
      "depthOrientation": {"type": "choice", "label": "Depth/Orientation", "options": ["Correct", "Shallow", "Deep"]},
      "paraffinOverflow": {"type": "boolean", "label": "Paraffin Overflow"}
    },
    "qcOutcome": {
      "qcStatus": {"type": "choice", "label": "QC Status", "options": ["Pass", "Fail"], "required": true},
      "qcRemarks": {"type": "textarea", "label": "QC Remarks"},
      "staffInitials": {"type": "text", "label": "Staff Initials", "required": true},
      "qcDate": {"type": "date", "label": "QC Date", "required": true}
    },
    "failActions": {
      "actionTaken": {"type": "choice", "label": "Action Taken", "options": ["Recollection requested", "Process with limitations", "Re-embed", "Melt block"], "conditionalOn": "qcStatus == Fail"},
      "notificationSent": {"type": "multiSelect", "label": "Notification Sent To", "options": ["Clinician", "PI", "Lab Head", "Pathologist"], "conditionalOn": "qcStatus == Fail"}
    }
  },
  "systemActions": ["Log QC status in accession record", "Update sample status: QC Passed or QC Failed - Action Required"],
  "nextPage": "Sample Processing & Aliquoting"
}

{
  "pageDescription": "Sample Processing & Aliquoting",
  "dataPoints": {
    "grossingAliquoting": {
      "processingAction": {"type": "choice", "label": "Processing Action", "options": ["Section to slides", "Aliquot for LBC", "Aliquot for cell block", "Aliquot for molecular testing", "Aliquot for biobanking"], "required": true},
      "parentAccessionNumber": {"type": "text", "label": "Parent Accession Number", "required": true},
      "childId": {"type": "text", "label": "Child Sample ID", "generated": true}
    },
    "histopathologyProcessing": {
      "grossExamDone": {"type": "boolean", "label": "Gross Examination Done", "conditionalOn": "specimenType.category == histopathology"},
      "grossDescription": {"type": "textarea", "label": "Gross Description", "conditionalOn": "specimenType.category == histopathology"},
      "sectioningDone": {"type": "boolean", "label": "Sectioning Done"},
      "tissueProcessing": {"type": "multiSelect", "label": "Tissue Processing Steps", "options": ["Alcohols", "Xylene", "Paraffin"], "conditionalOn": "specimenType.category == histopathology"},
      "embeddingDone": {"type": "boolean", "label": "Embedding Done"},
      "microtomyThickness": {"type": "number", "label": "Microtomy Thickness (um)", "default": 4}
    },
    "cytopathologyProcessing": {
      "centrifugationDone": {"type": "boolean", "label": "Centrifugation Done", "conditionalOn": "specimenType.category == cytopathology"},
      "smearType": {"type": "multiSelect", "label": "Smear Type", "options": ["Direct smear", "LBC (ThinPrep)", "Cell block"], "conditionalOn": "specimenType.category == cytopathology"},
      "stainUsed": {"type": "multiSelect", "label": "Stain Used", "options": ["Pap stain", "Romanowsky"]}
    },
    "bloodProcessing": {
      "wedgeSmearDone": {"type": "boolean", "label": "Wedge Smear Done", "conditionalOn": "specimenType.category == hematology"},
      "bloodStain": {"type": "choice", "label": "Blood Stain", "options": ["Giemsa", "Wright", "Giemsa/Wright"], "conditionalOn": "specimenType.category == hematology"}
    },
    "researchProcessing": {
      "sopFollowed": {"type": "text", "label": "SOP Reference", "conditionalOn": "sampleCategory == Research"},
      "processingMethod": {"type": "multiSelect", "label": "Processing Method", "options": ["LN2 freezing", "OCT embedding", "Nucleic acid extraction"], "conditionalOn": "sampleCategory == Research"}
    },
    "processingLog": {
      "processingStep": {"type": "text", "label": "Processing Step"},
      "processingDate": {"type": "date", "label": "Processing Date", "required": true},
      "staffInitials": {"type": "text", "label": "Staff Initials", "required": true}
    }
  },
  "systemActions": ["Log processing steps", "Create child samples", "Update sample status: Processing In Progress"],
  "nextPage": "Testing, Staining & Microscopy"
}

{
  "pageDescription": "Testing, Staining & Microscopy",
  "dataPoints": {
    "routineStains": {
      "stainType": {"type": "multiSelect", "label": "Routine Stain", "options": ["H&E", "Papanicolaou", "Romanowsky", "Giemsa", "Wright"]}
    },
    "specialStains": {
      "specialStainType": {"type": "multiSelect", "label": "Special Stain", "options": ["AFB", "GMS", "PAS", "Gram", "Trichrome", "Reticulin", "Iron"]}
    },
    "advancedTechniques": {
      "advancedType": {"type": "multiSelect", "label": "Advanced Technique", "options": ["IHC", "ICC", "ISH", "FISH"]},
      "ihcMarkers": {"type": "text", "label": "IHC/ICC Markers", "conditionalOn": "advancedType includes IHC or ICC"}
    },
    "researchAssays": {
      "researchAssayType": {"type": "multiSelect", "label": "Research Assay", "options": ["Laser microdissection", "Multiplex IHC", "Immunofluorescent staining", "RNAscope"], "conditionalOn": "sampleCategory == Research"}
    },
    "controls": {
      "positiveControlRun": {"type": "boolean", "label": "Positive Control Run"},
      "positiveControlResult": {"type": "choice", "label": "Positive Control Result", "options": ["Pass", "Fail"]},
      "negativeControlRun": {"type": "boolean", "label": "Negative Control Run"},
      "negativeControlResult": {"type": "choice", "label": "Negative Control Result", "options": ["Pass", "Fail"]},
      "assayAccepted": {"type": "boolean", "label": "Assay Accepted"}
    },
    "documentation": {
      "blockSlideId": {"type": "text", "label": "Block/Slide ID", "required": true},
      "testName": {"type": "text", "label": "Test Name", "required": true},
      "result": {"type": "textarea", "label": "Result", "required": true},
      "technicianSignature": {"type": "text", "label": "Technician Signature", "required": true},
      "pathologistVerification": {"type": "text", "label": "Pathologist Verification", "conditionalOn": "sampleCategory == Clinical diagnostic"}
    }
  },
  "systemActions": ["Link results to sample", "Update sample status: Results Pending Review"],
  "nextPage": "Storage & Inventory Management"
}

{
  "pageDescription": "Storage & Inventory Management",
  "dataPoints": {
    "storageConditions": {
      "storageType": {"type": "choice", "label": "Storage Type", "options": ["Room temperature cabinet", "4C refrigerator", "-20C freezer", "-80C freezer", "LN2 vapor", "Slide box"], "required": true},
      "expectedDuration": {"type": "text", "label": "Expected Storage Duration"}
    },
    "locationTracking": {
      "storageUnit": {"type": "text", "label": "Storage Unit (Cabinet/Freezer ID)", "required": true},
      "rack": {"type": "text", "label": "Rack", "required": true},
      "box": {"type": "text", "label": "Box", "required": true},
      "position": {"type": "text", "label": "Position", "placeholder": "e.g., A1, B3", "required": true},
      "dateStored": {"type": "dateTime", "label": "Date/Time Stored", "required": true},
      "storedBy": {"type": "text", "label": "Stored By", "required": true}
    },
    "retrieval": {
      "dateRetrieved": {"type": "dateTime", "label": "Date/Time Retrieved"},
      "retrievedBy": {"type": "text", "label": "Retrieved By"},
      "recipientSignature": {"type": "text", "label": "Recipient Signature"}
    },
    "environmentalMonitoring": {
      "temperatureCheckAM": {"type": "number", "label": "Temperature Check AM (C)"},
      "temperatureCheckPM": {"type": "number", "label": "Temperature Check PM (C)"},
      "checkedBy": {"type": "text", "label": "Checked By"},
      "checkDate": {"type": "date", "label": "Check Date"}
    }
  },
  "systemActions": ["Maintain location history", "Attach temperature logs"],
  "nextPage": "Reporting & Performance Monitoring"
}

{
  "pageDescription": "Reporting & Performance Monitoring",
  "dataPoints": {
    "routineReports": {
      "reportType": {"type": "choice", "label": "Report Type", "options": ["Monthly specimen volume", "Turnaround time (TAT)", "Rejection rates", "QC incidents", "Equipment downtime"]},
      "reportPeriod": {"type": "text", "label": "Report Period", "placeholder": "e.g., January 2025"},
      "generatedDate": {"type": "date", "label": "Generated Date"}
    },
    "keyMetrics": {
      "specimenRejectionRate": {"type": "number", "label": "Specimen Rejection Rate (%)"},
      "assaySuccessRate": {"type": "number", "label": "Assay Success Rate (%)"},
      "averageTAT": {"type": "number", "label": "Average TAT (hours)"},
      "equipmentDowntimeHours": {"type": "number", "label": "Equipment Downtime (hours)"}
    },
    "qcMeetings": {
      "meetingDate": {"type": "date", "label": "QC Meeting Date"},
      "attendees": {"type": "text", "label": "Attendees"},
      "issuesDiscussed": {"type": "textarea", "label": "Issues Discussed"},
      "actionsRequired": {"type": "textarea", "label": "Actions Required"}
    }
  },
  "systemActions": ["Generate dashboards", "Data used for QC meetings"],
  "nextPage": "Disposal & Archiving"
}

{
  "pageDescription": "Disposal & Archiving",
  "dataPoints": {
    "disposal": {
      "disposalReason": {"type": "choice", "label": "Disposal Reason", "options": ["Retention period expired", "Sample depleted", "Quality degradation", "Study completion", "Other"], "required": true},
      "retentionPolicy": {"type": "choice", "label": "Retention Policy Applied", "options": ["National clinical guidelines", "Research protocol", "Institutional policy"]},
      "disposalMethod": {"type": "choice", "label": "Disposal Method", "options": ["Incineration", "Autoclaving", "Chemical treatment", "Other"], "required": true},
      "disposalDate": {"type": "date", "label": "Disposal Date", "required": true},
      "staffSignature": {"type": "text", "label": "Staff Signature", "required": true},
      "unitHeadApproval": {"type": "text", "label": "Unit Head Approval", "required": true}
    },
    "archiving": {
      "archiveType": {"type": "multiSelect", "label": "Archive Type", "options": ["Physical - Logbooks", "Physical - Ledgers", "Physical - Reports", "Digital backup"]},
      "archiveLocation": {"type": "text", "label": "Archive Location", "placeholder": "e.g., Fire-proof cabinet A3"},
      "digitalBackupLocation": {"type": "text", "label": "Digital Backup Location", "placeholder": "e.g., Secure server /archives/2025"},
      "archiveDate": {"type": "date", "label": "Archive Date"}
    }
  },
  "systemActions": ["Mark sample as Closed", "Lock records"],
  "nextPage": "Reference & SOP Module"
}

{
  "pageDescription": "Reference & SOP Module",
  "dataPoints": {
    "sopRepository": {
      "sopTitle": {"type": "text", "label": "SOP Title"},
      "sopCategory": {"type": "choice", "label": "SOP Category", "options": ["Sample Reception", "Quality Control", "Processing", "Testing", "Storage", "Disposal", "Safety", "Equipment", "Other"]},
      "sopDocument": {"type": "file", "label": "SOP Document", "accept": ".pdf,.doc,.docx"},
      "version": {"type": "text", "label": "Version"},
      "effectiveDate": {"type": "date", "label": "Effective Date"},
      "reviewDate": {"type": "date", "label": "Review Date"}
    },
    "protocolUpdates": {
      "previousVersion": {"type": "text", "label": "Previous Version"},
      "changesSummary": {"type": "textarea", "label": "Summary of Changes"},
      "approvedBy": {"type": "text", "label": "Approved By"},
      "approvalDate": {"type": "date", "label": "Approval Date"}
    },
    "accessControl": {
      "viewAccessLevel": {"type": "text", "label": "View Access", "default": "All users", "readOnly": true},
      "editAccessLevel": {"type": "text", "label": "Edit Access", "default": "Lab managers, Supervisors", "readOnly": true}
    }
  },
  "systemActions": ["Store SOP documents", "Maintain version history", "Control access based on role"]
}
